SELECT TOP 1 COUNT(*) AS TRANSACTION_COUNT,
	SUM(PR.[AMOUNT]) AS DAILY_TOTAL 
FROM [PAYMENT_RECORDS] PR 
WHERE PR.[IsDeleted] = 0 
	AND PR.[PAYMENT_DATE] > DATEADD(DAY, -1,
	GETDATE()) 